-- Transaction 1:
BEGIN;
UPDATE accounts SET balance = balance - 100 WHERE id = 1; -- Lock A
UPDATE accounts SET balance = balance + 100 WHERE id = 2; -- Lock B
COMMIT;

-- Transaction 2:
BEGIN;
UPDATE accounts SET balance = balance - 50 WHERE id = 2;  -- Lock B
UPDATE accounts SET balance = balance + 50 WHERE id = 1;  -- Lock A
COMMIT;

-- AFTER - Consistent order (always lock by ID order)
BEGIN;
UPDATE accounts SET balance = balance - 100 WHERE id = 1; -- Lock lower ID first
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;

BEGIN;
UPDATE accounts SET balance = balance + 50 WHERE id = 1;  -- Lock lower ID first
UPDATE accounts SET balance = balance - 50 WHERE id = 2;
COMMIT;

-- Or use SELECT FOR UPDATE
BEGIN;
SELECT * FROM accounts WHERE id IN (1, 2) ORDER BY id FOR UPDATE;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;
```

