    // selectedIds = [101, 102, 103, 104, 105]

    const allItems = getAllItems();  // Returns all items from database
    // allItems = [{id: 201, ...}, {id: 202, ...}, ...]

    selectedIds.forEach(id => {
        // BUG: Using id as array index!
        delete allItems[id];  // Deletes allItems[101], allItems[102], etc.
    });
}

// Should be:
function bulkDelete(selectedIds) {
    selectedIds.forEach(id => {
        deleteItemById(id);  // Delete by actual ID, not index
    });
}
