from django.http import JsonResponse
from django.views.decorators.http import require_POST
from django.views.decorators.csrf import csrf_protect
import json
import logging

logger = logging.getLogger(__name__)

@require_POST
@csrf_protect
def bulk_delete_items(request):
    """
    Bulk delete items by ID.
    Returns list of actually deleted IDs for verification.
    """
    try:
        # Parse request body
        data = json.loads(request.body)
        ids_to_delete = data.get('ids', [])

        # Validate input
        if not ids_to_delete:
            return JsonResponse(
                {'error': 'No IDs provided'},
                status=400
            )

        if not isinstance(ids_to_delete, list):
            return JsonResponse(
                {'error': 'IDs must be a list'},
                status=400
            )

        # Convert to integers and validate
        try:
            ids_to_delete = [int(id) for id in ids_to_delete]
        except (ValueError, TypeError):
            return JsonResponse(
                {'error': 'All IDs must be integers'},
                status=400
            )

        # Log the operation
        logger.info(
            f"User {request.user.id} requesting bulk delete of "
            f"{len(ids_to_delete)} items: {ids_to_delete}"
        )

        # Get items that exist
        items_to_delete = Item.objects.filter(id__in=ids_to_delete)
        existing_ids = list(items_to_delete.values_list('id', flat=True))

        # Check for non-existent IDs
        non_existent = set(ids_to_delete) - set(existing_ids)
        if non_existent:
            logger.warning(f"Non-existent IDs requested: {non_existent}")

        # Perform deletion
        deleted_count, _ = items_to_delete.delete()

        # Log actual deletion
        logger.info(
            f"Successfully deleted {deleted_count} items. "
            f"IDs: {existing_ids}"
        )

        # Return deleted IDs for verification
        return JsonResponse({
            'success': True,
            'deleted_count': deleted_count,
            'deleted_ids': existing_ids,
            'non_existent_ids': list(non_existent)
        })

    except json.JSONDecodeError:
        return JsonResponse(
            {'error': 'Invalid JSON'},
            status=400
        )
    except Exception as e:
        logger.error(f"Error in bulk delete: {str(e)}")
        return JsonResponse(
            {'error': 'Internal server error'},
            status=500
        )
