**MOBILE IMAGE UPLOAD FAILURE**

### Problem
Profile image upload works on desktop but fails silently on mobile devices (iOS and Android).

### User Experience

**Desktop (Working)**:
1. Click "Upload Photo" button ✓
2. File picker opens ✓
3. Select image ✓
4. Upload starts automatically ✓
5. Progress bar shows ✓
6. Image appears ✓

**Mobile (Broken)**:
1. Tap "Upload Photo" button ✓
2. Photo picker opens ✓
3. Select image ✓
4. Nothing happens ✗
5. No progress indicator ✗
6. No error message ✗

### Root Causes

**1. Change Event Not Firing on Mobile**
```javascript
// WRONG - Doesn't work reliably on mobile
document.getElementById('photo-input').addEventListener('change', function() {
    uploadPhoto(this.files[0]);
});

// BETTER - Also handle input event
const input = document.getElementById('photo-input');
input.addEventListener('change', handlePhotoSelect);
input.addEventListener('input', handlePhotoSelect);  // Fallback for mobile
```

**2. Missing Accept Attribute**
```html
<!-- WRONG - No file type restriction -->
<input type="file" id="photo-input">

<!-- CORRECT - Specify image types -->
<input type="file" id="photo-input" 
       accept="image/*" 
       capture="user">
```

**3. File Size Issues on Mobile**
```javascript
// Mobile photos can be very large (10MB+)
// Need to resize before upload

function handlePhotoSelect(event) {
    const file = event.target.files[0];

    if (!file) return;

    // Check file size
    if (file.size > 10 * 1024 * 1024) {  // 10MB
        alert('Image too large. Resizing...');
        resizeImage(file, 1024, 1024).then(resizedFile => {
            uploadPhoto(resizedFile);
        });
    } else {
        uploadPhoto(file);
    }
}
```

**4. CORS Issues on Mobile**
```python
# Server needs proper CORS headers for mobile
from django.http import JsonResponse

def upload_photo(request):
    response = JsonResponse({'status': 'success'})
    response['Access-Control-Allow-Origin'] = '*'
    response['Access-Control-Allow-Methods'] = 'POST, OPTIONS'
    response['Access-Control-Allow-Headers'] = 'Content-Type'
    return response
```

### Complete Solution

**HTML**
```html
<div class="profile-photo-upload">
    <div class="current-photo">
        <img id="profile-img" src="{{ user.photo_url }}" alt="Profile">
    </div>

    <input type="file" 
           id="photo-input" 
           accept="image/*"
           capture="user"
           style="display: none;">

    <button id="upload-btn" class="btn-primary">
        📷 Upload Photo
    </button>

    <div id="upload-progress" style="display: none;">
        <div class="progress-bar">
            <div id="progress-fill" style="width: 0%"></div>
        </div>
        <span id="progress-text">Uploading...</span>
    </div>

    <div id="upload-error" class="error" style="display: none;"></div>
</div>
```

**JavaScript (Mobile-Compatible)**
```javascript
class ProfilePhotoUploader {
    constructor() {
        this.input = document.getElementById('photo-input');
        this.uploadBtn = document.getElementById('upload-btn');
        this.progressDiv = document.getElementById('upload-progress');
        this.progressFill = document.getElementById('progress-fill');
        this.progressText = document.getElementById('progress-text');
        this.errorDiv = document.getElementById('upload-error');
        this.profileImg = document.getElementById('profile-img');

        this.init();
    }

    init() {
        // Button triggers file input
        this.uploadBtn.addEventListener('click', () => {
            this.input.click();
        });

        // Handle file selection (both events for mobile compatibility)
        this.input.addEventListener('change', (e) => this.handleFileSelect(e));
        this.input.addEventListener('input', (e) => this.handleFileSelect(e));
    }

    handleFileSelect(event) {
        const file = event.target.files[0];

        if (!file) return;

        // Validate file type
        if (!file.type.startsWith('image/')) {
            this.showError('Please select an image file');
            return;
        }

        // Check file size (10MB max)
        const maxSize = 10 * 1024 * 1024;
        if (file.size > maxSize) {
            this.showError('Image too large (max 10MB)');
            return;
        }

        // Show preview
        this.showPreview(file);

        // Resize if needed (mobile photos are often huge)
        if (file.size > 1024 * 1024) {  // > 1MB
            this.resizeAndUpload(file);
        } else {
            this.uploadPhoto(file);
        }
    }

    showPreview(file) {
        const reader = new FileReader();
        reader.onload = (e) => {
            this.profileImg.src = e.target.result;
        };
        reader.readAsDataURL(file);
    }

    async resizeAndUpload(file) {
        try {
            this.showProgress('Resizing image...');

            const resizedBlob = await this.resizeImage(file, 800, 800);
            const resizedFile = new File([resizedBlob], file.name, {
                type: file.type
            });

            this.uploadPhoto(resizedFile);
        } catch (error) {
            this.showError('Error resizing image: ' + error.message);
        }
    }

    resizeImage(file, maxWidth, maxHeight) {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();

            reader.onload = (e) => {
                const img = new Image();

                img.onload = () => {
                    // Calculate new dimensions
                    let width = img.width;
                    let height = img.height;

                    if (width > height) {
                        if (width > maxWidth) {
                            height *= maxWidth / width;
                            width = maxWidth;
                        }
                    } else {
                        if (height > maxHeight) {
                            width *= maxHeight / height;
                            height = maxHeight;
                        }
                    }

                    // Create canvas
                    const canvas = document.createElement('canvas');
                    canvas.width = width;
                    canvas.height = height;

                    // Draw resized image
                    const ctx = canvas.getContext('2d');
                    ctx.drawImage(img, 0, 0, width, height);

                    // Convert to blob
                    canvas.toBlob((blob) => {
                        resolve(blob);
                    }, file.type, 0.9);
                };

                img.onerror = reject;
                img.src = e.target.result;
            };

            reader.onerror = reject;
            reader.readAsDataURL(file);
        });
    }

    async uploadPhoto(file) {
        try {
            this.showProgress('Uploading...');
            this.hideError();

            const formData = new FormData();
            formData.append('photo', file);

            const xhr = new XMLHttpRequest();

            // Track upload progress
            xhr.upload.addEventListener('progress', (e) => {
                if (e.lengthComputable) {
                    const percent = (e.loaded / e.total) * 100;
                    this.updateProgress(percent);
                }
            });

            // Handle completion
            xhr.addEventListener('load', () => {
                if (xhr.status === 200) {
                    const response = JSON.parse(xhr.responseText);
                    this.handleSuccess(response);
                } else {
                    this.showError('Upload failed: ' + xhr.statusText);
                }
            });

            // Handle errors
            xhr.addEventListener('error', () => {
                this.showError('Network error during upload');
            });

            xhr.addEventListener('abort', () => {
                this.showError('Upload cancelled');
            });

            // Send request
            xhr.open('POST', '/api/profile/upload-photo');
            xhr.send(formData);

        } catch (error) {
            this.showError('Error uploading photo: ' + error.message);
        }
    }

    showProgress(message) {
        this.progressDiv.style.display = 'block';
        this.progressText.textContent = message;
        this.uploadBtn.disabled = true;
    }

    updateProgress(percent) {
        this.progressFill.style.width = percent + '%';
        this.progressText.textContent = `Uploading... ${Math.round(percent)}%`;
    }

    hideProgress() {
        this.progressDiv.style.display = 'none';
        this.progressFill.style.width = '0%';
        this.uploadBtn.disabled = false;
    }

    handleSuccess(response) {
        this.hideProgress();
        this.profileImg.src = response.photo_url + '?t=' + Date.now();  // Cache bust

        // Show success message
        const successMsg = document.createElement('div');
        successMsg.className = 'success-message';
        successMsg.textContent = '✓ Photo updated successfully';
        this.uploadBtn.parentNode.appendChild(successMsg);

        setTimeout(() => successMsg.remove(), 3000);

        // Reset input
        this.input.value = '';
    }

    showError(message) {
        this.hideProgress();
        this.errorDiv.textContent = message;
        this.errorDiv.style.display = 'block';
    }

    hideError() {
        this.errorDiv.style.display = 'none';
    }
}

// Initialize when DOM ready
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
        new ProfilePhotoUploader();
    });
} else {
    new ProfilePhotoUploader();
}
```

**Backend (Python)**
```python
from django.http import JsonResponse
from django.views.decorators.http import require_POST
from PIL import Image
import io

@require_POST
def upload_profile_photo(request):
    try:
        photo = request.FILES.get('photo')

        if not photo:
            return JsonResponse(
                {'error': 'No photo provided'},
                status=400
            )

        # Validate file type
        if not photo.content_type.startswith('image/'):
            return JsonResponse(
                {'error': 'File must be an image'},
                status=400
            )

        # Validate file size (10MB max)
        if photo.size > 10 * 1024 * 1024:
            return JsonResponse(
                {'error': 'Image too large (max 10MB)'},
                status=400
            )

        # Process image
        img = Image.open(photo)

        # Convert to RGB if needed
        if img.mode in ('RGBA', 'P'):
            img = img.convert('RGB')

        # Resize to standard size
        img.thumbnail((800, 800), Image.Resampling.LANCZOS)

        # Save to storage
        output = io.BytesIO()
        img.save(output, format='JPEG', quality=90)
        output.seek(0)

        # Save to user profile
        filename = f'profile_photos/{request.user.id}.jpg'
        path = default_storage.save(filename, output)
        photo_url = default_storage.url(path)

        # Update user profile
        request.user.profile.photo = path
        request.user.profile.save()

        return JsonResponse({
