**JavaScript (Modal Management)**
```javascript
class SessionTimeoutManager {
    constructor() {
        this.warningTime = 60;  // Show warning 60 seconds before timeout
        this.sessionDuration = 30 * 60;  // 30 minutes
        this.countdownInterval = null;
        this.timeoutTimer = null;
        this.warningTimer = null;

        this.container = document.getElementById('session-timeout-container');
        this.countdown = document.getElementById('timeout-countdown');
        this.extendBtn = document.getElementById('extend-session-btn');
        this.logoutBtn = document.getElementById('logout-btn');

        this.init();
    }

    init() {
        // Attach event listeners
        this.extendBtn.addEventListener('click', () => this.extendSession());
        this.logoutBtn.addEventListener('click', () => this.logout());

        // Start session timer
        this.resetSessionTimer();

        // Reset timer on user activity
        this.setupActivityListeners();
    }

    setupActivityListeners() {
        const events = ['mousedown', 'keypress', 'scroll', 'touchstart'];

        events.forEach(event => {
            document.addEventListener(event, () => {
                if (!this.isModalVisible()) {
                    this.resetSessionTimer();
                }
            }, { passive: true });
        });
    }

    resetSessionTimer() {
        // Clear existing timers
        clearTimeout(this.warningTimer);
        clearTimeout(this.timeoutTimer);

        // Set warning timer
        const warningDelay = (this.sessionDuration - this.warningTime) * 1000;
        this.warningTimer = setTimeout(() => {
            this.showWarning();
        }, warningDelay);

        // Set timeout timer
        this.timeoutTimer = setTimeout(() => {
            this.logout();
        }, this.sessionDuration * 1000);
    }

    showWarning() {
        // Ensure modal is at body level (not nested)
        if (this.container.parentElement !== document.body) {
            document.body.appendChild(this.container);
        }

        // Show modal
        this.container.style.display = 'block';
        document.body.classList.add('modal-open');

        // Start countdown
        let remaining = this.warningTime;
        this.updateCountdown(remaining);

        this.countdownInterval = setInterval(() => {
            remaining--;
            this.updateCountdown(remaining);

            if (remaining <= 0) {
                clearInterval(this.countdownInterval);
                this.logout();
            }
        }, 1000);

        // Focus on extend button for accessibility
        this.extendBtn.focus();

        // Trap focus in modal
        this.trapFocus();
    }

    updateCountdown(seconds) {
        this.countdown.textContent = seconds;

        // Change color as time runs out
        if (seconds <= 10) {
            this.countdown.style.color = '#d32f2f';  // Red
        } else if (seconds <= 30) {
            this.countdown.style.color = '#f57c00';  // Orange
        } else {
            this.countdown.style.color = '#1976d2';  // Blue
        }
    }

    hideWarning() {
        clearInterval(this.countdownInterval);
        this.container.style.display = 'none';
        document.body.classList.remove('modal-open');
    }

    async extendSession() {
        try {
            // Call server to extend session
            const response = await fetch('/api/auth/extend-session', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-CSRFToken': this.getCsrfToken()
                }
            });

            if (response.ok) {
                this.hideWarning();
                this.resetSessionTimer();

                // Show success message
                this.showToast('Session extended successfully', 'success');
            } else {
                throw new Error('Failed to extend session');
            }
        } catch (error) {
            this.showToast('Error extending session', 'error');
            console.error(error);
        }
    }

    logout() {
        window.location.href = '/logout?reason=timeout';
    }

    isModalVisible() {
        return this.container.style.display !== 'none';
    }

    trapFocus() {
        const focusableElements = this.container.querySelectorAll(
            'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );

        const firstElement = focusableElements[0];
        const lastElement = focusableElements[focusableElements.length - 1];

        this.container.addEventListener('keydown', (e) => {
            if (e.key === 'Tab') {
                if (e.shiftKey) {
                    if (document.activeElement === firstElement) {
                        e.preventDefault();
                        lastElement.focus();
                    }
                } else {
                    if (document.activeElement === lastElement) {
                        e.preventDefault();
                        firstElement.focus();
                    }
                }
            }

            // Close on Escape
            if (e.key === 'Escape') {
                this.extendSession();
            }
        });
    }

    getCsrfToken() {
        return document.querySelector('[name=csrfmiddlewaretoken]')?.value || '';
    }

    showToast(message, type) {
        const toast = document.createElement('div');
        toast.className = `toast toast-${type}`;
        toast.textContent = message;
        document.body.appendChild(toast);

        setTimeout(() => toast.remove(), 3000);
    }
}

// Initialize
const sessionManager = new SessionTimeoutManager();
```

