**JavaScript Print Helper**
```javascript
class PrintHelper {
    static preparePrint() {
        // Add print-specific classes
        document.body.classList.add('printing');

        // Expand collapsed sections
        document.querySelectorAll('.collapsed').forEach(el => {
            el.classList.add('expanded-for-print');
        });

        // Show hidden data
        document.querySelectorAll('.truncated').forEach(el => {
            el.classList.add('full-for-print');
        });
    }

    static cleanupPrint() {
        document.body.classList.remove('printing');

        document.querySelectorAll('.expanded-for-print').forEach(el => {
            el.classList.remove('expanded-for-print');
        });

        document.querySelectorAll('.full-for-print').forEach(el => {
            el.classList.remove('full-for-print');
        });
    }

    static print() {
        this.preparePrint();

        // Wait for DOM updates
        setTimeout(() => {
            window.print();
            this.cleanupPrint();
        }, 100);
    }

    static printElement(elementId) {
        const element = document.getElementById(elementId);
        if (!element) return;

        // Create print window
        const printWindow = window.open('', '', 'width=800,height=600');

        // Copy styles
        const styles = Array.from(document.styleSheets)
            .map(sheet => {
                try {
                    return Array.from(sheet.cssRules)
                        .map(rule => rule.cssText)
                        .join('\n');
                } catch (e) {
                    return '';
                }
            })
            .join('\n');

        // Write content
        printWindow.document.write(`
            <!DOCTYPE html>
            <html>
            <head>
                <title>Print</title>
                <style>${styles}</style>
            </head>
            <body>
                ${element.innerHTML}
            </body>
            </html>
        `);

        printWindow.document.close();

        // Print after load
        printWindow.onload = () => {
            printWindow.print();
            printWindow.close();
        };
    }
}

// Usage
document.getElementById('print-btn').addEventListener('click', () => {
    PrintHelper.print();
});

// Listen for print events
window.addEventListener('beforeprint', () => {
    console.log('Preparing to print...');
    PrintHelper.preparePrint();
});

window.addEventListener('afterprint', () => {
    console.log('Print complete');
    PrintHelper.cleanupPrint();
});
```

**Advanced: Generate PDF Server-Side**
```python
from django.http import HttpResponse
from weasyprint import HTML, CSS
from django.template.loader import render_to_string

def generate_pdf_report(request, report_id):
    # Get report data
    report = Report.objects.get(id=report_id)

    # Render HTML template
    html_string = render_to_string('reports/print_template.html', {
        'report': report,
        'data': report.get_data()
    })

    # Convert to PDF
    html = HTML(string=html_string)
    css = CSS(string='''
        @page {
            size: A4;
            margin: 2cm;
        }
        body {
            font-family: Arial, sans-serif;
        }
        table {
            width: 100%;
            border-collapse: collapse;
        }
        th, td {
            border: 1px solid #000;
            padding: 8px;
        }
    ''')

    pdf = html.write_pdf(stylesheets=[css])

    # Return PDF
    response = HttpResponse(pdf, content_type='application/pdf')
    response['Content-Disposition'] = f'attachment; filename="report_{report_id}.pdf"'

    return response
```

