```javascript
// Debug print styles
function debugPrintStyles() {
    // Get all stylesheets
    const printStyles = [];

    Array.from(document.styleSheets).forEach(sheet => {
        try {
            Array.from(sheet.cssRules).forEach(rule => {
                if (rule.media && rule.media.mediaText.includes('print')) {
                    printStyles.push(rule.cssText);
                }
            });
        } catch (e) {
            console.warn('Cannot access stylesheet:', sheet.href);
        }
    });

    console.log('Print styles:', printStyles);

    // Check element visibility for print
    const element = document.querySelector('.print-container');
    const computedStyle = window.getComputedStyle(element, '@media print');

    console.log('Print display:', computedStyle.display);
    console.log('Print visibility:', computedStyle.visibility);
}
